17: // TriggerPolicyUpdates triggers the policy update trigger.
18: //
19: // To follow what the trigger does, see NewUpdater.
20: func (u *Updater) TriggerPolicyUpdates(force bool, reason string) {
21: 	if force {
22: 		log.Debugf("Artificially increasing policy revision to enforce policy recalculation")
23: 		u.repo.BumpRevision()
24: 	}
25: 
26: 	u.TriggerWithReason(reason)
27: }
