29: // NewUpdater returns a new Updater instance to handle triggering policy
30: // updates ready for use.
31: func NewUpdater(r *Repository, regen regenerator) *Updater {
32: 	t, err := trigger.NewTrigger(trigger.Parameters{
33: 		Name:            "policy_update",
34: 		MetricsObserver: &TriggerMetrics{},
35: 		MinInterval:     option.Config.PolicyTriggerInterval,
36: 		// Triggers policy updates for every local endpoint.
37: 		// This may be called in a variety of situations: after policy changes,
38: 		// changes in agent configuration, changes in endpoint labels, and
39: 		// change of security identities.
40: 		TriggerFunc: func(reasons []string) {
41: 			log.Debug("Regenerating all endpoints")
42: 			reason := strings.Join(reasons, ", ")
43: 
44: 			regenerationMetadata := &regeneration.ExternalRegenerationMetadata{
45: 				Reason:            reason,
46: 				RegenerationLevel: regeneration.RegenerateWithoutDatapath,
47: 			}
48: 			regen.RegenerateAllEndpoints(regenerationMetadata)
49: 		},
50: 	})
51: 	if err != nil {
52: 		panic(err) // unreachable, only occurs if TriggerFunc is nil
53: 	}
54: 	return &Updater{
55: 		Trigger: t,
56: 		repo:    r,
57: 	}
58: }
