import (
	"context"
	"sync"

	"github.com/cilium/hive/cell"
	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/clustermesh"
	"github.com/cilium/cilium/pkg/clustermesh/wait"
	"github.com/cilium/cilium/pkg/endpoint/regeneration"
	"github.com/cilium/cilium/pkg/logging/logfields"
	"github.com/cilium/cilium/pkg/time"
)

var (
	RegeneratorCell = cell.Module(
		"endpoint-regeneration",
		"Endpoints regeneration",

		cell.Provide(newRegenerator),
	)
)

// KVStoreNodesWaitFn is the type of the function used to wait for synchronization
// of all nodes from the kvstore.
type KVStoreNodesWaitFn wait.Fn

// EndpointsSource is an interface for accessing endpoints.
type EndpointsSource interface {
	// GetEndpoints returns a slice of all endpoints.
	GetEndpoints() []*Endpoint
}

// Regenerator wraps additional functionalities for endpoint regeneration.
type Regenerator struct {
	nodesWaitFn   KVStoreNodesWaitFn
	cmWaitFn      wait.Fn
	cmWaitTimeout time.Duration

	logger        logrus.FieldLogger
	cmSyncLogOnce sync.Once
}

// EndpointRegenerator wraps endpoint regeneration logic.
type EndpointRegenerator struct {
	source EndpointsSource
	logger logrus.FieldLogger
}

func newRegenerator(in struct {
	cell.In

	Logger logrus.FieldLogger

	Config      wait.TimeoutConfig
	NodesWaitFn KVStoreNodesWaitFn
	ClusterMesh *clustermesh.ClusterMesh
}) *Regenerator {
	waitFn := func(context.Context) error { return nil }
	if in.ClusterMesh != nil {
		waitFn = in.ClusterMesh.IPIdentitiesSynced
	}

	return &Regenerator{
		logger:        in.Logger,
		nodesWaitFn:   in.NodesWaitFn,
		cmWaitFn:      waitFn,
		cmWaitTimeout: in.Config.Timeout(),
	}
}

// NewEndpointRegenerator creates a new EndpointRegenerator.
func NewEndpointRegenerator(source EndpointsSource, logger logrus.FieldLogger) *EndpointRegenerator {
	return &EndpointRegenerator{
		source: source,
		logger: logger,
	}
}

// CapTimeoutForSynchronousRegeneration caps the timeout to a value suitable in
// case the regeneration of an endpoint needs to be performed synchronously
// (currently required when IPSec is enabled). In particular, this is necessary
// to not block the agent bootstrap, as that prevents the scheduling of new
// workloads. This logic is implemented as a separate function to avoid
// forgetting to remove it when the synchronous regeneration is removed.
func (r *Regenerator) CapTimeoutForSynchronousRegeneration() {
	const maxTimeout = 5 * time.Second
	if r.cmWaitTimeout > maxTimeout {
		r.cmWaitTimeout = maxTimeout
		r.logger.WithField(logfields.Value, maxTimeout).
			Info("Capped clustermesh-sync-timeout because endpoint regeneration needs to be performed synchronously")
	}
}

func (r *Regenerator) WaitForKVStoreNodesSync(ctx context.Context) error {
	return r.nodesWaitFn(ctx)
}

func (r *Regenerator) WaitForClusterMeshIPIdentitiesSync(ctx context.Context) error {
	wctx, cancel := context.WithTimeout(ctx, r.cmWaitTimeout)
	defer cancel()
	err := r.cmWaitFn(wctx)

	switch {
	case ctx.Err() != nil:
		// The context associated with the endpoint has been canceled.
		return ErrNotAlive
	case err != nil:
		// We don't return an error in case the wait operation timed out, as we can
		// continue with the endpoint regeneration, although at the cost of possible
		// connectivity drops for cross-cluster connections. We additionally print
		// the warning message only once, to avoid repeating it for every endpoint.
		r.cmSyncLogOnce.Do(func() {
			r.logger.Warning("Failed waiting for clustermesh IPs and identities synchronization before regenerating endpoints, expect possible disruption of cross-cluster connections")
		})
	}

	return nil
}

// RegenerateAllEndpoints calls a setState for each endpoint and
// regenerates if state transaction is valid. During this process, the endpoint
// list is locked and cannot be modified.
// Returns a waiting group that can be used to know when all the endpoints are
// regenerated.
func (er *EndpointRegenerator) RegenerateAllEndpoints(regenMetadata *regeneration.ExternalRegenerationMetadata) *sync.WaitGroup {
	var wg sync.WaitGroup

	eps := er.source.GetEndpoints()
	wg.Add(len(eps))

	// Dereference "reason" field outside of logging statement; see
	// https://github.com/sirupsen/logrus/issues/1003.
	reason := regenMetadata.Reason
	er.logger.WithField("reason", reason).Info("regenerating all endpoints")
	for _, ep := range eps {
		go func(ep *Endpoint) {
			<-ep.RegenerateIfAlive(regenMetadata)
			wg.Done()
		}(ep)
	}

	return &wg
}

// WaitForEndpointsAtPolicyRev waits for all endpoints which existed at the time
// this function is called to be at a given policy revision.
// New endpoints appearing while waiting are ignored.
func (er *EndpointRegenerator) WaitForEndpointsAtPolicyRev(ctx context.Context, rev uint64) error {
	eps := er.source.GetEndpoints()
	for i := range eps {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-eps[i].WaitForPolicyRevision(ctx, rev, nil):
			if ctx.Err() != nil {
				return ctx.Err()
			}
		}
	}
	return nil
}

